use eframe::egui; struct App; impl eframe::App for App { fn update(&mut self, ctx: &egui::Context, frame: &mut eframe::Frame) { if ctx.input(|i| i.viewport().close_requested()) { ctx.send_viewport_cmd(egui::ViewportCommand::CancelClose); ctx.send_viewport_cmd(egui::ViewportCommand::Visible(false)); } } } fn main() { eframe::run_native("Test", eframe::NativeOptions::default(), Box::new(|_| Ok(Box::new(App)))); }
